#include <stdio.h>
#include <string.h>
#include <math.h>

int val(char* s, int c) {
    int ssum = 0;
    for (int i = 0; s[i]; i++) {
        if (s[i] == '+') ssum++;
        else if (s[i] == '-') ssum--;
    }
    return ssum;
}

int val2(char* s, int c) {
    int ssum = 0;
    for (int i = 0; s[i]; i++) {
        if (s[i] == '1') ssum++;
        else if (s[i] == '0') ssum--;
    }
    ssum -= (c - strlen(s));
    return ssum;
}

int main() {
    char send[100], recv[100];
    scanf("%s", send);
    scanf("%s", recv);

    int needed_val = val(send, strlen(send));
    int rval = val(recv, strlen(recv));

    if (strchr(recv, '?') == NULL) {
        if (needed_val == rval) {
            printf("1\n");
            return 0;
        } else {
            printf("0\n");
            return 0;
        }
    }

    int ques = 0;
    for (int i = 0; recv[i]; i++) {
        if (recv[i] == '?') ques++;
    }
    int fav = 0;

    for (int i = 0; i < (1 << ques); i++) {
        char binary[20];
        int tmp = i;
        int idx = 0;
        while (tmp > 0) {
            binary[idx++] = (tmp % 2) + '0';
            tmp /= 2;
        }
        binary[idx] = '\0';
        int tmp_val = val2(binary, ques) + rval;
        if (tmp_val == needed_val) {
            fav++;
        }
    }

    printf("%.12f\n", (double)fav / pow(2, ques));
    return 0;
}
